import os
import openpyxl

def verify(workspace_path, external_services_path=None):
    TARGET_CELLS = ["AF4", "AF6", "AF7", "AF9"]
    # Accept either "OPEN — handoff" (em dash) or "OPEN - handoff" (hyphen)
    ACCEPTED_VALUES = {"OPEN — handoff", "OPEN - handoff"}

    # ── locate workbook ──────────────────────────────────────────────────────
    wb_path = os.path.join(workspace_path, "receiving_log.xlsx")
    if not os.path.isfile(wb_path):
        return {
            "pass": False,
            "score": 0,
            "feedback": "receiving_log.xlsx not found in workspace.",
        }

    try:
        wb = openpyxl.load_workbook(wb_path, data_only=True)
        ws = wb.active
    except Exception as exc:
        return {
            "pass": False,
            "score": 0,
            "feedback": f"Could not open receiving_log.xlsx: {exc}",
        }

    # ── check each hard-coded cell ───────────────────────────────────────────
    failures = []
    for cell_ref in TARGET_CELLS:
        value = ws[cell_ref].value
        if value is None:
            failures.append(f"{cell_ref} is empty.")
            continue
        # Compare exact string (no lowercasing, no stripping) so that only
        # "OPEN — handoff" or "OPEN - handoff" pass.
        if str(value).strip() not in ACCEPTED_VALUES:
            failures.append(
                f"{cell_ref} contains '{value}' — expected 'OPEN — handoff'."
            )

    if failures:
        return {
            "pass": False,
            "score": 0,
            "feedback": "FAIL — " + " | ".join(failures),
        }

    return {
        "pass": True,
        "score": 1,
        "feedback": (
            "PASS — AF4, AF6, AF7, and AF9 all contain 'OPEN — handoff'."
        ),
    }

import os
import re
import openpyxl
from pathlib import Path

def verify(workspace_path, external_services_path=None):
    # Check that cell AD9 in receiving_log.xlsx notes that
    # Elizabeth has NOT acknowledged.

    TARGET_CELL = "AD9"

    # Patterns meaning "Elizabeth has not acknowledged" —
    # all require an explicit negation; bare "ack" or "elizabeth" alone do not pass.
    NOT_ACK_RE = re.compile(
        r"""
          not\s+(?:yet\s+)?acknowledged
        | not\s+(?:yet\s+)?ack(?:nowledged)?
        | has\s+not\s+(?:yet\s+)?ack(?:nowledged)?
        | hasn['']?t\s+(?:yet\s+)?ack(?:nowledged)?
        | did\s+not\s+ack(?:nowledge)?
        | didn['']?t\s+ack(?:nowledge)?
        | failed\s+to\s+ack(?:nowledge)?
        | no\s+ack(?:nowledgement|nowledgment)?
        | pending\s+ack(?:nowledgement|nowledgment)?
        | awaiting\s+ack(?:nowledgement|nowledgment)?
        | unacknowledged
        | without\s+ack(?:nowledgement|nowledgment)?
        | missing\s+ack(?:nowledgement|nowledgment)?
        | no\s+confirmation\s+(?:from|received)
        | not\s+confirmed
        | ack(?:nowledgement|nowledgment)(?=.{0,100}(?:still\s+)?(?:open|pending|outstanding))
        """,
        re.VERBOSE | re.IGNORECASE | re.DOTALL,
    )

    # ── locate workbook ──────────────────────────────────────────────────────
    wb_path = os.path.join(workspace_path, "receiving_log.xlsx")
    if not os.path.isfile(wb_path):
        candidates = list(Path(workspace_path).glob("**/receiving_log.xlsx"))
        if candidates:
            wb_path = str(candidates[0])
        else:
            return {"pass": False, "score": 0,
                    "feedback": "receiving_log.xlsx not found in workspace."}

    try:
        wb = openpyxl.load_workbook(wb_path, data_only=True)
        ws = wb.active
    except Exception as exc:
        return {"pass": False, "score": 0,
                "feedback": f"Could not open receiving_log.xlsx: {exc}"}

    # ── read target cell ─────────────────────────────────────────────────────
    notes_val = ws[TARGET_CELL].value

    if notes_val is None or str(notes_val).strip() == "":
        return {"pass": False, "score": 0,
                "feedback": f"FAIL — Cell {TARGET_CELL} is empty."}

    notes_lower = str(notes_val).lower()

    if "elizabeth" not in notes_lower:
        return {
            "pass": False, "score": 0,
            "feedback": (
                f"FAIL — Cell {TARGET_CELL} does not mention Elizabeth. "
                f"Content: '{notes_val}'."
            ),
        }

    if not NOT_ACK_RE.search(notes_lower):
        return {
            "pass": False, "score": 0,
            "feedback": (
                f"FAIL — Cell {TARGET_CELL} mentions Elizabeth but does not "
                f"clearly state that she has not acknowledged. "
                f"Content: '{notes_val}'."
            ),
        }

    return {
        "pass": True,
        "score": 1,
        "feedback": (
            f"PASS — Cell {TARGET_CELL} notes that Elizabeth has not "
            f"acknowledged. Content: '{notes_val}'."
        ),
    }

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    workspace = Path(workspace_path)

    # Look for slack data in both external_services_path and workspace
    slack_data = None
    candidates = []

    if external_services_path:
        esp = Path(external_services_path)
        candidates.append(esp / 'slack_data.json')
        candidates.append(esp / 'slack-data.json')

    candidates.append(workspace / 'slack_data.json')
    candidates.append(workspace / 'slack-data.json')

    slack_file_used = None
    for candidate in candidates:
        if candidate.exists():
            try:
                slack_data = json.loads(candidate.read_text(encoding='utf-8', errors='replace'))
                slack_file_used = str(candidate)
                break
            except Exception:
                continue

    if slack_data is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'No slack_data.json or slack-data.json found in workspace or external services path.'}

    # Find the #receiving-dock channel id
    target_channel_name = 'receiving-dock'
    target_channel_id = None
    channels = slack_data.get('channels', {})
    if isinstance(channels, dict):
        for ch_id, ch in channels.items():
            if isinstance(ch, dict):
                name = (ch.get('name') or ch.get('name_normalized') or '').lstrip('#').lower()
                if name == target_channel_name:
                    target_channel_id = ch_id
                    break

    if target_channel_id is None:
        return {'pass': False, 'score': 0.0, 'feedback': f'Channel #{target_channel_name} not found in {slack_file_used}.'}

    # Collect message texts ONLY from the #receiving-dock channel
    all_texts = []
    messages = slack_data.get('messages', {})
    channel_messages = messages.get(target_channel_id, []) if isinstance(messages, dict) else []
    if isinstance(channel_messages, list):
        for msg in channel_messages:
            if isinstance(msg, dict):
                text = msg.get('text', '')
                if text:
                    all_texts.append(text)

    if not all_texts:
        return {'pass': False, 'score': 0.0, 'feedback': f'No messages found in channel #{target_channel_name} in {slack_file_used}.'}

    # Date: require 04/14/2026 exact MM/DD/YYYY format per rubric, but also accept common variants
    date_pattern = re.compile(r'04[/\-]14[/\-]2026|2026[/\-]04[/\-]14|april\s+14[,\s]+2026|14[/\-]04[/\-]2026', re.IGNORECASE)
    # Initials: SM - be generous with matching
    initials_pattern = re.compile(r'\bSM\b|\bS\.?\s*M\.?\b', re.IGNORECASE)

    found_date = False
    found_initials = False
    date_msg_excerpt = None
    initials_msg_excerpt = None
    matching_msg = None

    for text in all_texts:
        has_date = bool(date_pattern.search(text))
        has_initials = bool(initials_pattern.search(text))
        if has_date and has_initials:
            found_date = True
            found_initials = True
            matching_msg = text[:200]
            break
        if has_date and not found_date:
            found_date = True
            date_msg_excerpt = text[:100]
        if has_initials and not found_initials:
            found_initials = True
            initials_msg_excerpt = text[:100]

    if found_date and found_initials:
        if matching_msg:
            return {'pass': True, 'score': 1.0, 'feedback': f'Handoff post with date 04/14/2026 and initials SM found in a single message in #{target_channel_name} ({slack_file_used}). Excerpt: "{matching_msg}"'}
        else:
            return {'pass': True, 'score': 1.0, 'feedback': f'Date 04/14/2026 and initials SM found across messages in #{target_channel_name} in {slack_file_used}. Date in: "{date_msg_excerpt}", Initials in: "{initials_msg_excerpt}"'}

    issues = []
    if not found_date:
        issues.append(f'Date 04/14/2026 not found in any message in #{target_channel_name}')
    if not found_initials:
        issues.append(f'Initials SM not found in any message in #{target_channel_name}')

    sample_texts = all_texts[:5]
    debug_info = f' | Sample messages from #{target_channel_name} ({len(all_texts)} total): ' + ' /// '.join([t[:150] for t in sample_texts])

    return {'pass': False, 'score': 0.2, 'feedback': '; '.join(issues) + debug_info}

