    search_texts = receiving_dock_texts if receiving_dock_texts else all_texts
    if not search_texts:
        return {"pass": False, "score": 0, "feedback": "No Slack messages found."}

    # ── find the 04/14/2026 handoff post ─────────────────────────────────────
    HANDOFF_RE = re.compile(r'END[\s\-]*OF[\s\-]*SHIFT\s+HANDOFF\s+04/14/2026', re.IGNORECASE)

