import json
import re

def verify(workspace_path, external_services_path=None):
    # Rubric: The handoff post in 'slack_data.json' must include a QUARANTINE STATUS
    # section listing all 4 active quarantines (Q-HOLD entries) including one from a
    # prior shift: (REC-20260408-001, REC-20260414-003, REC-20260414-005, REC-20260414-007)
    # with a total dollar estimate of approximately $76,712.

    # ── locate slack_data.json ───────────────────────────────────────────────
    slack_data = None
    slack_file_used = None
    candidates = []
    if external_services_path:
        esp = Path(external_services_path)
        candidates += [esp / "slack_data.json", esp / "slack-data.json"]
    candidates += [
        Path(workspace_path) / "slack_data.json",
        Path(workspace_path) / "slack-data.json",
    ]
    for c in candidates:
        if c.exists():
            try:
                slack_data = json.loads(c.read_text(encoding="utf-8", errors="replace"))
                slack_file_used = str(c)
                break
            except Exception:
                continue

    if slack_data is None:
        return {"pass": False, "score": 0,
                "feedback": "No slack_data.json / slack-data.json found."}

    # ── collect messages from #receiving-dock ────────────────────────────────
    messages_by_channel = slack_data.get("messages", {})
    channels_meta = slack_data.get("channels", {})

    all_texts = []
    receiving_dock_texts = []

    if isinstance(messages_by_channel, dict):
        for ch_id, msg_list in messages_by_channel.items():
            ch_name = ""
            if isinstance(channels_meta, dict):
                ch_info = channels_meta.get(ch_id, {})
                ch_name = (ch_info.get("name") or "").lower() if isinstance(ch_info, dict) else ""
            is_receiving = "receiving" in ch_name or "receiving" in ch_id.lower() or "dock" in ch_name
            if isinstance(msg_list, list):
                for msg in msg_list:
                    if isinstance(msg, dict):
                        text = msg.get("text", "")
                        if text:
                            all_texts.append(text)
                            if is_receiving:
                                receiving_dock_texts.append(text)

    search_texts = receiving_dock_texts if receiving_dock_texts else all_texts

    if not search_texts:
        return {"pass": False, "score": 0,
                "feedback": f"No messages found in {slack_file_used}."}

    # ── find the 04/14/2026 handoff post ────────────────────────────────────
    # Pin to 04/14/2026 — prior-shift JT post (04/13) must not match
    HANDOFF_HEADER_RE = re.compile(
        r'END[\s\-]*OF[\s\-]*SHIFT\s+HANDOFF\s+04/14/2026',
        re.IGNORECASE,
    )

    handoff_post = None
    for text in search_texts:
        if HANDOFF_HEADER_RE.search(text):
            handoff_post = text
            break

    # Fallback: any 04/14/2026 message mentioning quarantine and REC- IDs
    if handoff_post is None:
        for text in search_texts:
            if (re.search(r'04/14/2026', text) and
                    re.search(r'quarantine', text, re.IGNORECASE) and
                    re.search(r'REC-', text)):
                handoff_post = text
                break

    if handoff_post is None:
        return {"pass": False, "score": 0,
                "feedback": "No 04/14/2026 handoff post found in Slack messages."}

    # ── extract QUARANTINE STATUS section ────────────────────────────────────
    quarantine_section = None
    section_split = re.split(r'\n(?=[A-Z][A-Z\s\/]+:)', handoff_post)
    for i, section in enumerate(section_split):
        if re.match(r'\s*QUARANTINE', section, re.IGNORECASE):
            quarantine_section = "\n".join(section_split[i:])
            break

    # If no explicit section header, search the whole post
    search_text = quarantine_section if quarantine_section else handoff_post

    # ── check required quarantine IDs ────────────────────────────────────────
    # Full IDs required — abbreviated forms (REC-003 etc.) are not SOP-compliant
    required_ids = {
        "REC-20260408-001": r"REC[\s\-]?20260408[\s\-]?001",
        "REC-20260414-003": r"REC[\s\-]?20260414[\s\-]?003",
        "REC-20260414-005": r"REC[\s\-]?20260414[\s\-]?005",
        "REC-20260414-007": r"REC[\s\-]?20260414[\s\-]?007",
    }

    found_ids = []
    missing_ids = []
    for label, pattern in required_ids.items():
        if re.search(pattern, search_text, re.IGNORECASE):
            found_ids.append(label)
        else:
            missing_ids.append(label)

    # ── check dollar estimate ────────────────────────────────────────────────
    # ±5% tolerance — rubric says "approximately"
    target_value = 76712
    tolerance = 0.05
    low = target_value * (1 - tolerance)
    high = target_value * (1 + tolerance)

    dollar_ok = False
    found_dollar = None

    # Standard amounts: $76,712 or $76712
    for amt_str in re.findall(r'\$\s*([\d,]+(?:\.\d{1,2})?)', search_text):
        try:
            amt = float(amt_str.replace(',', ''))
            if low <= amt <= high:
                dollar_ok = True
                found_dollar = amt
                break
        except ValueError:
            continue

    # K-abbreviated amounts: $76.7K, $76.7k, $77K etc.
    if not dollar_ok:
