import re
import json

def verify(workspace_path, external_services_path=None):
    HANDOFF_RE = re.compile(
        r'END[\s\-]*OF[\s\-]*SHIFT\s+HANDOFF\s+04/14/2026', re.IGNORECASE
    )
    SECTION_RE = re.compile(r'NOTES\s+FOR\s+TOMORROW', re.IGNORECASE)

    # ── locate slack_data.json ────────────────────────────────────────────────
    candidates = []
    if external_services_path:
        ep = Path(external_services_path)
        candidates += [ep / "slack_data.json", ep / "slack-data.json"]
    candidates += [
        Path(workspace_path) / "slack_data.json",
        Path(workspace_path) / "slack-data.json",
    ]
    slack_data = None
    for c in candidates:
        if c.exists():
            try:
                slack_data = json.loads(c.read_text(encoding="utf-8", errors="replace"))
                break
            except Exception:
                continue

    if slack_data is None:
        return {"pass": False, "score": 0,
                "feedback": "No slack_data.json found."}

    # ── collect all message texts ─────────────────────────────────────────────
    all_texts = []
    messages = slack_data.get("messages", {})
    if isinstance(messages, dict):
        for ch_id, msg_list in messages.items():
            if isinstance(msg_list, list):
                for msg in msg_list:
                    if isinstance(msg, dict):
                        t = msg.get("text", "")
                        if t:
                            all_texts.append(t)
    elif isinstance(messages, list):
        for msg in messages:
            if isinstance(msg, dict):
                t = msg.get("text", "")
                if t:
                    all_texts.append(t)

    if not all_texts:
        return {"pass": False, "score": 0, "feedback": "No messages found in slack_data.json."}

    # ── find the 04/14/2026 handoff post ─────────────────────────────────────
    handoff_post = None
