        failures.append("AX-04827-B2 not referenced in NOTES FOR TOMORROW section.")

    if not re.search(r'line[\s\-_.]?down|linedown', notes_section, re.IGNORECASE):
        failures.append("Line-down risk not referenced in NOTES FOR TOMORROW section.")

    if failures:
