from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    slack_path = None
    candidates = []

    if external_services_path:
        ep = Path(external_services_path)
        candidates += [ep / "slack_data.json", ep / "slack-data.json"]
    candidates += [
        Path(workspace_path) / "slack_data.json",
        Path(workspace_path) / "slack-data.json",
    ]

    for c in candidates:
        if c.exists():
            slack_path = c
            break

    if slack_path is None:
        return {"pass": False, "score": 0,
                "feedback": "Could not find slack_data.json in workspace or external services path."}

    try:
        with open(slack_path, 'r', encoding='utf-8') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0, "feedback": f"Failed to parse slack_data.json: {e}"}

    # ── collect messages ─────────────────────────────────────────────────────
    all_message_texts = []
    messages_dict = slack_data.get("messages", {})
    if isinstance(messages_dict, dict):
        for channel_id, msg_list in messages_dict.items():
            if isinstance(msg_list, list):
                for msg in msg_list:
                    if isinstance(msg, dict):
                        text = msg.get("text", "")
                        if text:
                            all_message_texts.append(text)

    if not all_message_texts:
        return {"pass": False, "score": 0, "feedback": "No messages found in slack_data.json."}

    # ── find the handoff post ────────────────────────────────────────────────
    HANDOFF_RE = re.compile(r'END[\s\-]*OF[\s\-]*SHIFT\s+HANDOFF\s+04/14/2026', re.IGNORECASE)

    handoff_text = None
    for text in all_message_texts:
        if HANDOFF_RE.search(text):
            handoff_text = text
            break

    # Fallback: any message with OPEN ESCALATIONS
    if handoff_text is None:
        for text in all_message_texts:
            if re.search(r'OPEN\s+ESCALATION', text, re.IGNORECASE):
                handoff_text = text
                break

    if handoff_text is None:
        return {"pass": False, "score": 0,
                "feedback": "No 04/14/2026 handoff post with OPEN ESCALATIONS found in slack_data.json."}

    # ── extract OPEN ESCALATIONS section only ────────────────────────────────
    esc_match = re.search(r'OPEN\s+ESCALATIONS?', handoff_text, re.IGNORECASE)
    if not esc_match:
        return {"pass": False, "score": 0,
                "feedback": "OPEN ESCALATIONS header not found in handoff post."}

    # Truncate at the next section header so later sections (QUARANTINE STATUS etc.)
    # don't pollute the REC-003 negative check
    after_header = handoff_text[esc_match.end():]
    next_section = re.search(r'\n[A-Z][A-Z\s/]+:', after_header)
    escalations_section = after_header[:next_section.start()] if next_section else after_header

    # ── check required IDs present ───────────────────────────────────────────
    has_005 = bool(re.search(r'REC[\-\s]?20260414[\-\s]?005', escalations_section, re.IGNORECASE))
    has_007 = bool(re.search(r'REC[\-\s]?20260414[\-\s]?007', escalations_section, re.IGNORECASE))

    # ── check REC-003 is absent ──────────────────────────────────────────────
    has_003 = bool(re.search(r'REC[\-\s]?20260414[\-\s]?003', escalations_section, re.IGNORECASE))

    issues = []
    if not has_005:
        issues.append("REC-20260414-005 missing from OPEN ESCALATIONS section.")
    if not has_007:
        issues.append("REC-20260414-007 missing from OPEN ESCALATIONS section.")
    if has_003:
        issues.append("REC-20260414-003 should NOT be listed in OPEN ESCALATIONS "
                      "(Darnell Hooks acknowledged — escalation resolved).")

    if issues:
        snippet = escalations_section[:800].replace("\n", " ")
        return {"pass": False, "score": 0,
                "feedback": "FAIL — " + "; ".join(issues) +
                            f" OPEN ESCALATIONS content: \"{snippet}\""}

    return {"pass": True, "score": 1,
            "feedback": "PASS — OPEN ESCALATIONS lists REC-20260414-005 and REC-20260414-007; "
                        "REC-20260414-003 correctly absent (escalation resolved)."}

from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
