    #   AD6: must name Walter Finch or Darnell Hooks as ack owner.
    #   AD9: must name Elizabeth Velasquez or Walter Finch as ack owner.

    AD_1BASED = 30  # column AD

    # ── locate workbook ──────────────────────────────────────────────────────
    wb_path = Path(workspace_path) / "receiving_log.xlsx"
    if not wb_path.exists():
        candidates = list(Path(workspace_path).glob("**/receiving_log.xlsx"))
        if not candidates:
