        wb = openpyxl.load_workbook(wb_path, data_only=True)
        ws = wb.active
    except Exception as exc:
        return {"pass": False, "score": 0,
                "feedback": f"Could not open receiving_log.xlsx: {exc}"}

    # ── header sanity ────────────────────────────────────────────────────────
    h_ad = str(ws.cell(row=1, column=AD_1BASED).value or "").strip()
    if h_ad != "Handoff_Notes":
        return {"pass": False, "score": 0,
                "feedback": f"Header sanity: column AD is '{h_ad}', expected 'Handoff_Notes'."}

    # ── read target cells ────────────────────────────────────────────────────
    ad6_val = ws["AD6"].value
    ad9_val = ws["AD9"].value
    ad6 = str(ad6_val) if ad6_val is not None else ""
    ad9 = str(ad9_val) if ad9_val is not None else ""

    failures = []

    # ── AD6: Walter Finch or Darnell Hooks ───────────────────────────────────
    has_walter_ad6  = bool(re.search(r"walter\s+finch|walter\b", ad6, re.IGNORECASE))
    has_darnell_ad6 = bool(re.search(r"darnell\s+hooks|darnell\b", ad6, re.IGNORECASE))
    if not (has_walter_ad6 or has_darnell_ad6):
        failures.append(
            f"AD6 does not name Walter Finch or Darnell Hooks as escalation ack owner. "
            f"Cell value: '{ad6[:200]}'"
        )

    # ── AD9: Elizabeth Velasquez or Walter Finch ─────────────────────────────
    has_elizabeth_ad9 = bool(re.search(r"elizabeth\s+velasquez|elizabeth\b", ad9, re.IGNORECASE))
    has_walter_ad9    = bool(re.search(r"walter\s+finch|walter\b", ad9, re.IGNORECASE))
    if not (has_elizabeth_ad9 or has_walter_ad9):
        failures.append(
            f"AD9 does not name Elizabeth Velasquez or Walter Finch as escalation ack owner. "
            f"Cell value: '{ad9[:200]}'"
        )

